// React Router DOM Development Version
// This is a simplified version for local development
// In production, you should use the official CDN

window.ReactRouterDOM = {
  BrowserRouter: function BrowserRouter({ children }) {
    return children;
  },
  Routes: function Routes({ children }) {
    return children;
  },
  Route: function Route({ children }) {
    return children;
  },
  useSearchParams: function useSearchParams() {
    return new URLSearchParams(window.location.search);
  },
  useNavigate: function useNavigate() {
    return function(path) {
      window.location.href = path;
    };
  }
};

console.log('ReactRouterDOM loaded locally');
